window.PACTO.acts["reg-2021-1147"]={"label": "REGOLAMENTO (UE) 2021/1147 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2021/1147", "file": "ext-reg-2021-1147.html", "external": true, "version": "consolidato 2026-07-01", "eurlex": "https://eur-lex.europa.eu/eli/reg/2021/1147/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Il presente regolamento istituisce il Fondo Asilo, migrazione e integrazione («Fondo») per il periodo che va dal 1<span class=\"superscript\">o</span> gennaio 2021 al 31 dicembre 2027.</p>"], [null, "<p class=\"norm\">Esso stabilisce gli obiettivi del Fondo, la dotazione di bilancio per il periodo dal 1<span class=\"superscript\">o</span> gennaio 2021 al 31 dicembre 2027, le forme di finanziamento dell’Unione e le regole di erogazione dei finanziamenti.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento si applicano le seguenti definizioni:</p>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«richiedente protezione internazionale»: un richiedente quale definito all’articolo 2, punto 4), del regolamento (UE) 2024/1351 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">1</span>\n);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«beneficiario di protezione internazionale»: un beneficiario di protezione internazionale quale definito all’articolo 2, punto 7), del regolamento (UE) 2024/1351;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«operazione di finanziamento misto»: un’azione sostenuta dal bilancio dell’Unione, anche nell’ambito dei meccanismi di finanziamento misto ai sensi dell’articolo 2, punto 6), del regolamento finanziario;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«familiare»: un familiare quale definito all’articolo 2, punto 8), del regolamento (UE) 2024/1351;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«ammissione umanitaria»: l’ammissione umanitaria quale definita all’articolo 2, punto 3), del regolamento (UE) 2024/1350 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n);</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«sostegno operativo»: una parte della dotazione di uno Stato membro che può essere utilizzata come sostegno alle autorità pubbliche responsabili dello svolgimento dei compiti e della fornitura dei servizi che costituiscono un servizio pubblico per l’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«allontanamento»: l’allontanamento come definito all’articolo 3, punto 5, della direttiva 2008/115/CE;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«reinsediamento»: il reinsediamento quale definito all’articolo 2, punto 1), del regolamento (UE) 2024/1350;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«rimpatrio»: il rimpatrio come definito all’articolo 3, punto 3, della direttiva 2008/115/CE;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>10) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«azioni specifiche»: progetti transnazionali o nazionali che recano un valore aggiunto dell’Unione in linea con gli obiettivi del Fondo per il quale uno, più o tutti gli Stati membri possono ricevere una dotazione aggiuntiva per i loro programmi;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>11) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«cittadino di paese terzo»: un cittadino di paese terzo quale definito all’articolo 2, punto 1, del regolamento (UE) 2024/1351;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>12) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«minore non accompagnato», un minore non accompagnato quale definito all’articolo 2, punto 11), del regolamento (UE) 2024/1351;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>13) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«azioni dell’Unione»: progetti transnazionali o progetti di particolare interesse per l’Unione attuati conformemente agli obiettivi del Fondo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>14) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«persona vulnerabile»: una persona definita persona vulnerabile a norma del diritto dell’Unione pertinente al settore di azione sostenuto dal Fondo;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>15) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«azione di solidarietà»: un’azione il cui ambito di applicazione è definito all’articolo 56, paragrafo 2, lettera b), del regolamento (UE) 2024/1351, finanziata dai contributi finanziari forniti dagli Stati membri di cui all’articolo 64, paragrafo 1, di tale regolamento.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "3": {"label": "Articolo 3", "heading": "Obiettivi del Fondo", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’obiettivo strategico del Fondo è contribuire a una gestione efficace dei flussi migratori e all’attuazione, al rafforzamento e allo sviluppo della politica comune in materia di asilo e della politica comune in materia di immigrazione, in conformità del pertinente acquis dell’Unione e nel pieno rispetto degli obblighi internazionali derivanti dagli strumenti internazionali di cui l’Unione e gli Stati membri sono parte.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito dell’obiettivo strategico di cui al paragrafo 1, il Fondo contribuisce ai seguenti obiettivi specifici:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rafforzare e sviluppare tutti gli aspetti del sistema europeo comune di asilo, compresa la sua dimensione esterna;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rafforzare e sviluppare la migrazione legale verso gli Stati membri secondo le rispettive esigenze economiche e sociali, nonché promuovere e contribuire all’effettiva integrazione e inclusione sociale dei cittadini di paesi terzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contribuire a combattere la migrazione irregolare, favorire rimpatri e riammissioni efficaci, sicuri e dignitosi e promuovere e contribuire a un’efficace reintegrazione iniziale nei paesi terzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">migliorare la solidarietà e l’equa ripartizione della responsabilità tra gli Stati membri, in particolare per quanto riguarda quelli più esposti alle sfide in materia di migrazione e asilo, anche attraverso una cooperazione pratica.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nell’ambito degli obiettivi specifici di cui al paragrafo 2, il Fondo è attuato mediante le misure di attuazione di cui all’allegato II.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Partenariato", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">Ai fini del presente Fondo, a norma dell’articolo 8, paragrafo 1, del regolamento (UE) 2021/1060, i partenariati includono le autorità regionali, locali, cittadine e altre autorità pubbliche o le associazioni che rappresentano tali autorità, le pertinenti organizzazioni internazionali, le organizzazioni non governative, quali le organizzazioni di rifugiati e quelle guidate da migranti, nonché le istituzioni nazionali operanti nell’ambito dei diritti umani e gli organismi per le pari opportunità nonché le parti economiche e sociali.</p>"]]}, "5": {"label": "Articolo 5", "heading": "Ambito di applicazione del sostegno", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nell’ambito dei suoi obiettivi e in linea con le misure di attuazione di cui all’allegato II, il Fondo sostiene in particolare le azioni elencate nell’allegato III.</div>\n</div>"], [null, "<p class=\"norm\">Per far fronte a circostanze impreviste o nuove, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 per modificare l’elenco delle azioni di cui all’allegato III, al fine di aggiungere nuove azioni.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per conseguire i suoi obiettivi, il Fondo può sostenere, in linea con le priorità dell’Unione, le azioni di cui all’allegato III e in relazione ai paesi terzi, se del caso, in conformità dell’articolo 7 o 24, a seconda dei casi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per quanto riguarda le azioni nei paesi terzi e in relazione a tali paesi, la Commissione e gli Stati membri, insieme al servizio europeo per l’azione esterna, assicurano, conformemente alle rispettive competenze, il coordinamento con le politiche, le strategie e gli strumenti pertinenti dell’Unione. Provvedono in particolare affinché le azioni nei paesi terzi e in relazione a tali paesi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano svolte in sinergia e coerenza con altre azioni esterne all’Unione sostenute da altri strumenti dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano coerenti con la politica esterna dell’Unione, rispettino il principio della coerenza delle politiche per lo sviluppo e siano coerenti con i documenti di programmazione strategica per la regione o il paese in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano incentrate su misure non orientate allo sviluppo; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">servano gli interessi delle politiche interne dell’Unione e siano coerenti con le attività intraprese all’interno dell’Unione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli obiettivi del Fondo sostengono azioni incentrate su uno o più gruppi di riferimento che rientrano nell’ambito di applicazione degli articoli 78 e 79 TFUE.</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Parità di genere e non discriminazione", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e la Commissione garantiscono l’integrazione della prospettiva di genere e provvedono affinché la parità di genere e l’integrazione di genere siano prese in considerazione e promosse in tutte le fasi della preparazione, dell’attuazione, della sorveglianza, della rendicontazione e della valutazione dei programmi e dei progetti sostenuti nell’ambito del Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri e la Commissione adottano le misure necessarie per prevenire qualsiasi forma di discriminazione vietata dall’articolo 21 della Carta dei diritti fondamentali dell’Unione europea («Carta») nelle fasi di preparazione, attuazione, sorveglianza, rendicontazione e valutazione dei programmi e dei progetti sostenuti nell’ambito del Fondo.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Paesi terzi associati al Fondo", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il Fondo è aperto ai paesi terzi che soddisfano i criteri di cui al paragrafo 2, alle condizioni stabilite in un accordo specifico relativo alla partecipazione del paese terzo in questione al Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Affinché sia ammissibile a essere associato al Fondo secondo quanto previsto al paragrafo 1, il paese terzo deve aver concluso un accordo con l’Unione sui criteri e i meccanismi di determinazione dello Stato competente per l’esame di una domanda di asilo presentata in uno Stato membro o in tale paese terzo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Come minimo, l’accordo specifico riguardante la partecipazione del paese terzo al Fondo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">consente la cooperazione con gli Stati membri e le istituzioni, gli organi e gli organismi dell’Unione in materia di asilo, migrazione e rimpatrio, nello spirito dei principi di solidarietà e di equa ripartizione della responsabilità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si fonda, per tutta la durata del Fondo, sui principi di non respingimento, di democrazia, dello Stato di diritto e sul rispetto dei diritti umani;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce un giusto equilibrio tra i contributi e i benefici per il paese terzo che partecipa al Fondo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabilisce le condizioni per la partecipazione al Fondo, compreso il calcolo dei contributi finanziari al Fondo, e i suoi costi amministrativi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non conferisce al paese terzo alcun potere decisionale riguardo al Fondo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantisce all’Unione il diritto di assicurare una sana gestione finanziaria e di tutelare i propri interessi finanziari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabilisce che il paese terzo conceda i diritti necessari e l’accesso di cui hanno bisogno l’ordinatore responsabile, l’OLAF e la Corte dei conti a norma dell’articolo 8.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">I contributi di cui alla lettera d) del primo comma costituiscono entrate con destinazione specifica ai sensi dell’articolo 21, paragrafo 5, del regolamento finanziario</p>"]]}, "8": {"label": "Articolo 8", "heading": "Tutela degli interessi finanziari dell’Unione", "anchor": "art_8", "frags": [[null, "<p class=\"norm\">Allorché un paese terzo partecipa al Fondo mediante una decisione adottata a norma di un accordo internazionale o sulla base di qualsiasi altro strumento giuridico, il paese terzo concede i diritti necessari e l’accesso di cui hanno bisogno l’ordinatore responsabile, l’OLAF e la Corte dei conti per esercitare integralmente le rispettive competenze. Nel caso dell’OLAF, tali diritti comprendono il diritto di effettuare indagini, anche attraverso controlli e verifiche sul posto, in conformità del regolamento (UE, Euratom) n. 883/2013.</p>"]]}, "9": {"label": "Articolo 9", "heading": "Principi generali", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il sostegno fornito nell’ambito del Fondo integra l’intervento nazionale, regionale e locale e mira ad apportare il valore aggiunto dell’Unione al conseguimento degli obiettivi del Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri garantiscono che il sostegno fornito nell’ambito del Fondo e dagli Stati membri sia coerente con le pertinenti azioni, politiche e priorità dell’Unione e sia complementare rispetto al sostegno fornito nell’ambito degli altri strumenti dell’Unione, in particolare gli strumenti esterni, il Fondo sociale europeo Plus (FSE+) e il Fondo europeo di sviluppo regionale (FESR).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il Fondo è attuato in regime di gestione diretta, concorrente o indiretta in conformità dell’articolo 62, paragrafo 1, primo comma, lettere a), b) e c), del regolamento finanziario.</div>\n</div>"]]}, "10": {"label": "Articolo 10", "heading": "Bilancio", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La dotazione finanziaria per l’attuazione del Fondo per il periodo dal 1<span class=\"superscript\">o</span> gennaio 2021 al 31 dicembre 2027 ammonta a 9 882 000 000  EUR a prezzi correnti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La dotazione finanziaria è così utilizzata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">6 270 000 000  EUR sono stanziati per i programmi degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">3 612 000 000  EUR sono stanziati per lo strumento tematico di cui all’articolo 11.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Su iniziativa della Commissione, fino allo 0,42 % della dotazione finanziaria è destinato all’assistenza tecnica di cui all’articolo 35 del regolamento (UE) 2021/1060.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">A norma dell’articolo 26 del regolamento (UE) 2021/1060, fino al 5 % della dotazione iniziale a uno Stato membro proveniente da uno qualsiasi dei fondi nell’ambito di tale regolamento in regime di gestione concorrente può essere trasferito al Fondo in regime di gestione diretta o indiretta, su richiesta di tale Stato membro. La Commissione dà esecuzione a tali risorse direttamente, in conformità dell’articolo 62, paragrafo 1, primo comma, lettera a), del regolamento finanziario, o indirettamente, in conformità di tale comma. Tali risorse sono utilizzate a beneficio dello Stato membro interessato.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il sostegno fornito nell’ambito del presente regolamento può essere finanziato anche mediante contributi degli Stati membri e di altri donatori pubblici o privati come entrate con destinazione specifica esterne a norma dell’articolo 21, paragrafo 5, del regolamento finanziario.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "11": {"label": "Articolo 11", "heading": "Disposizioni generali di attuazione dello strumento tematico", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’importo di cui all’articolo 10, paragrafo 2, lettera b), è stanziato in maniera flessibile mediante uno strumento tematico in regime di gestione concorrente, diretta o indiretta, secondo quanto stabilito nei programmi di lavoro. Data la natura interna del Fondo, lo strumento tematico serve principalmente la politica interna dell’Unione in linea con gli obiettivi specifici di cui all’articolo 3, paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm inline-element\">I finanziamenti dello strumento tematico sono usati per le componenti dello strumento stesso, che sono le seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni specifiche;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le azioni dell’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’assistenza emergenziale di cui all’articolo 31;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il reinsediamento e l’ammissione umanitaria;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sostegno agli Stati membri per il trasferimento di richiedenti protezione internazionale o di beneficiari di protezione internazionale nell’ambito di sforzi di solidarietà di cui all’articolo 20; e</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la rete europea sulle migrazioni di cui all’articolo 26.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">L’assistenza tecnica su iniziativa della Commissione, di cui all’articolo 35 del regolamento (UE) 2021/1060, riceve sostegno anche dall’importo di cui all’articolo 10, paragrafo 2, lettera b), del presente regolamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I finanziamenti dello strumento tematico sono usati per affrontare priorità con un elevato valore aggiunto dell’Unione o per rispondere a necessità urgenti, in linea con le priorità concordate dell’Unione di cui all’allegato II.</div>\n</div>"], [null, "<p class=\"norm\">I finanziamenti di cui primo comma del presente paragrafo, a eccezione di quelli utilizzati per l’assistenza emergenziale a norma dell’articolo 31, paragrafo 1, primo comma, lettere a) e b), sostengono unicamente le azioni elencate nell’allegato III, compresi il reinsediamento e l’ammissione umanitaria conformemente all’articolo 19, nell’ambito della dimensione esterna della politica migratoria dell’Unione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione avvia un dialogo con le organizzazioni della società civile e le reti pertinenti, in particolare al fine di preparare e valutare i programmi di lavoro per le azioni dell’Unione finanziate nell’ambito del Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Almeno il 20 % delle risorse della dotazione iniziale destinata allo strumento tematico è assegnato all’obiettivo specifico di cui all’articolo 3, paragrafo 2, lettera d).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Quando i finanziamenti dello strumento tematico sono erogati agli Stati membri in regime di gestione diretta o indiretta, la Commissione provvede affinché non siano selezionati i progetti oggetto di un parere motivato espresso dalla Commissione relativo a procedure di infrazione a norma dell’articolo 258 TFUE che mettano in dubbio la legittimità e la regolarità delle spese o la performance di tali progetti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ai fini dell’articolo 23 e dell’articolo 24, paragrafo 2, del regolamento (UE) 2021/1060, qualora i finanziamenti dello strumento tematico siano attuati in regime di gestione concorrente, lo Stato membro interessato garantisce, e la Commissione si assicura, che le azioni previste non siano oggetto di un parere motivato espresso dalla Commissione relativo a procedure di infrazione a norma dell’articolo 258 TFUE che mettano in dubbio la legittimità e la regolarità delle spese o la performance delle azioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione stabilisce l’importo totale da mettere a disposizione per lo strumento tematico nell’ambito degli stanziamenti annuali del bilancio dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La Commissione adotta, mediante atti di esecuzione, decisioni di finanziamento di cui all’articolo 110 del regolamento finanziario riguardanti lo strumento tematico che identificano gli obiettivi e le azioni da sostenere e specificano gli importi di ciascuna delle sue componenti di cui al paragrafo 1, secondo comma, del presente articolo. Le decisioni di finanziamento stabiliscono, se del caso, l’importo globale destinato alle operazioni di finanziamento misto. Le decisioni di finanziamento possono essere annuali o pluriennali e possono riguardare una o più componenti dello strumento tematico di cui al paragrafo 1, secondo comma, del presente articolo. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 38, paragrafo 3, del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Lo strumento tematico sostiene segnatamente azioni di sostegno rientranti nella misura di attuazione di cui all’allegato II, punto 2, lettera d), che sono attuate da autorità nazionali, regionali e locali o da organizzazioni della società civile. A tale riguardo, almeno il 5 % della dotazione iniziale destinata allo strumento tematico è assegnato all’attuazione delle misure di integrazione da parte delle autorità locali e regionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">La Commissione garantisce che la distribuzione delle risorse tra gli obiettivi specifici di cui all’articolo 3, paragrafo 2, sia equa e trasparente. La Commissione riferisce in merito all’utilizzo e alla distribuzione dello strumento tematico tra le componenti di cui al paragrafo 1, secondo comma, del presente articolo, compreso il sostegno fornito alle azioni nei paesi terzi o in relazione a tali paesi nell’ambito delle azioni dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">A seguito dell’adozione della decisione di finanziamento di cui al paragrafo 8, la Commissione può modificare di conseguenza i programmi degli Stati membri.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Ambito di applicazione", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La presente sezione si applica all’importo di cui all’articolo 10, paragrafo 2, lettera a), e alle risorse addizionali da attuare in regime di gestione concorrente conformemente alla decisione di finanziamento riguardante lo strumento tematico di cui all’articolo 11.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il sostegno nell’ambito della presente sezione è attuato in regime di gestione concorrente in conformità dell’articolo 63 del regolamento finanziario e del regolamento (UE) 2021/1060.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Risorse di bilancio", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’importo di cui all’articolo 10, paragrafo 2, lettera a), è stanziato per i programmi degli Stati membri indicativamente come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">5 225 000 000  EUR conformemente all’allegato I;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">1 045 000 000  EUR per l’adeguamento delle dotazioni ai programmi degli Stati membri di cui all’articolo 17, paragrafo 1.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora l’importo di cui al paragrafo 1, lettera b), del presente articolo non sia totalmente assegnato, l’importo residuo può essere aggiunto all’importo di cui all’articolo 10, paragrafo 2, lettera b).</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Prefinanziamento", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Conformemente all’articolo 90, paragrafo 4, del regolamento (UE) 2021/1060, il prefinanziamento per il Fondo è versato in frazioni annuali prima del 1<span class=\"superscript\">o</span> luglio di ogni anno, subordinatamente alla disponibilità di finanziamenti, come indicato nel seguito:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2021: 4 %</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2022: 3 %</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2023: 5 %</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2024: 5 %</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2025: 5 %</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">2026: 5 %</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se un programma di uno Stato membro è adottato dopo il 1<span class=\"superscript\">o</span> luglio 2021, le frazioni precedenti sono versate nell’anno della sua adozione.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Tassi di cofinanziamento", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione non supera il 75 % del totale delle spese ammissibili per un progetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 90 % del totale delle spese ammissibili per i progetti attuati nell’ambito di azioni specifiche.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 90 % del totale delle spese ammissibili per le azioni elencate all’allegato IV.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 100 % del totale delle spese ammissibili coperte dal sostegno operativo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 100 % del totale delle spese ammissibili per l’assistenza emergenziale di cui all’articolo 31.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 100 % del totale delle spese ammissibili per l’assistenza tecnica su iniziativa degli Stati membri, entro i limiti di cui all’articolo 36, paragrafo 5, lettera b), punto vi), del regolamento (UE) 2021/1060.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M3\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6 bis.  </span>\n<div class=\"norm inline-element\">Il contributo a carico del bilancio dell’Unione può essere aumentato fino al 100 % del totale delle spese ammissibili per le azioni di solidarietà.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La decisione della Commissione che approva un programma di uno Stato membro fissa il tasso di cofinanziamento e l’importo massimo del sostegno del Fondo per le tipologie di azione oggetto del contributo di cui ai paragrafi da 1 a 6.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La decisione della Commissione che approva un programma di uno Stato membro indica per ciascuna tipologia di azione se il tasso di cofinanziamento è applicato rispetto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al contributo totale, che comprende il contributo pubblico e il contributo privato; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">solo al contributo pubblico.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Programmi degli Stati membri", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro garantisce che le priorità affrontate nel proprio programma siano coerenti con le priorità e le sfide dell’Unione nel settore della gestione dell’asilo e della migrazione, rispondano a tali sfide e priorità e siano pienamente conformi al pertinente acquis dell’Unione e alle priorità concordate dell’Unione, nel pieno rispetto degli obblighi internazionali dell’Unione e degli Stati membri derivanti dagli strumenti internazionali di cui sono parti. Nel definire le priorità dei loro programmi gli Stati membri garantiscono che le misure di attuazione elencate nell’allegato II siano adeguatamente trattate nei loro programmi.</div>\n</div>"], [null, "<p class=\"norm\">Data la natura interna del Fondo, i programmi degli Stati membri servono principalmente la politica interna dell’Unione in linea con gli obiettivi specifici di cui all’articolo 3, paragrafo 2, del presente regolamento.</p>"], [null, "<p class=\"norm\">La Commissione valuta i programmi degli Stati membri in conformità dell’articolo 23 del regolamento (UE) 2021/1060.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito delle risorse assegnate a norma dell’articolo 13, paragrafo 1, e fatto salvo il paragrafo 3 del presente articolo, ogni Stato membro assegna nell’ambito del proprio programma:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno il 15 % delle proprie risorse assegnate all’obiettivo specifico di cui all’articolo 3, paragrafo 2, lettera a); e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno il 15 % delle proprie risorse assegnate all’obiettivo specifico di cui all’articolo 3, paragrafo 2, lettera b).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può stanziare meno della percentuale minima di cui al paragrafo 2 unicamente qualora motivi in maniera dettagliata la scelta nel proprio programma spiegando i motivi per cui l’assegnazione di risorse inferiori a tale soglia non pregiudichi il conseguimento dell’obiettivo pertinente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione garantisce che le conoscenze e le competenze delle pertinenti agenzie decentrate dell’Unione, in particolare l’EASO, l’Agenzia europea della guardia di frontiera e costiera e l’Agenzia dell’Unione europea per i diritti fondamentali, istituita dal regolamento (CE) n. 168/2007 (\n<span class=\"superscript\">3</span>\n), siano prese in considerazione per le materie di loro competenza, in una fase iniziale e in modo tempestivo, nello sviluppo dei programmi degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se del caso, la Commissione può coinvolgere le pertinenti agenzie decentrate, comprese quelle di cui al paragrafo 4, ai compiti di sorveglianza e valutazione specificati alla sezione 5, in particolare per garantire che le azioni attuate con il sostegno del Fondo siano conformi al pertinente acquis dell’Unione e alle priorità concordate dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">In seguito all’adozione di raccomandazioni in conformità del regolamento (UE) n. 1053/2013 rientranti nell’ambito di applicazione del presente regolamento, lo Stato membro interessato valuta, insieme alla Commissione, come dare seguito ai risultati e alle raccomandazioni attraverso il proprio programma, se del caso, con il sostegno del Fondo.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione può anche avvalersi, se del caso, delle competenze di agenzie decentrate in merito a questioni specifiche che rientrano nella loro sfera di competenza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Se necessario, il programma dello Stato membro in questione è modificato conformemente all’articolo 24 del regolamento (UE) 2021/1060 per tenere conto delle raccomandazioni di cui al paragrafo 6 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">In cooperazione e in consultazione con la Commissione e con le pertinenti agenzie decentrate per quanto riguarda i settori delle loro competenze, se del caso, lo Stato membro interessato può riassegnare le risorse stanziate nell’ambito del proprio programma, per tenere conto delle raccomandazioni di cui al paragrafo 6 nel caso in cui tali raccomandazioni abbiano implicazioni finanziarie.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Gli Stati membri perseguono in particolare le azioni ammissibili a tassi di cofinanziamento più elevati elencati nell’allegato IV nei loro programmi. In caso di circostanze impreviste o nuove o per garantire l’efficiente attuazione dei finanziamenti, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 per modificare l’elenco delle azioni ammissibili a tassi di cofinanziamento più elevati di cui all’allegato IV.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">I programmi degli Stati membri possono consentire l’inclusione di parenti stretti delle persone oggetto delle misure di integrazione di cui all’allegato III nella misura necessaria all’efficace attuazione di tali misure.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che decida di attuare un progetto sostenuto dal Fondo con un paese terzo o in un paese terzo consulta la Commissione prima dell’approvazione del progetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">La programmazione di cui all’articolo 22, paragrafo 5, del regolamento (UE) 2021/1060 è basata sulle tipologie di intervento indicate nella tabella 1 dell’allegato VI del presente regolamento e comprende una ripartizione indicativa delle risorse programmate per tipologia di intervento nell’ambito di ciascun obiettivo specifico di cui all’articolo 3, paragrafo 2, del presente regolamento.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Riesame intermedio", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nel 2024 la Commissione assegna ai programmi degli Stati membri interessati l’importo aggiuntivo di cui all’articolo 13, paragrafo 1, lettera b), conformemente ai criteri di cui all’allegato I, punto 1, lettera b), e punti da 2 a 5. Il finanziamento ha effetto a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2025.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora almeno il 10 % della dotazione iniziale a un programma di cui all’articolo 13, paragrafo 1, lettera a), del presente regolamento non è stato oggetto di domande di pagamento presentate conformemente all’articolo 91 del regolamento (UE) 2021/1060, lo Stato membro interessato non è ammesso a ricevere la dotazione aggiuntiva per il rispettivo programma di cui all’articolo 13, paragrafo 1, lettera b), del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nell’assegnazione dei fondi provenienti dallo strumento tematico di cui all’articolo 11 del presente regolamento a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2025 la Commissione tiene conto dei progressi compiuti dagli Stati membri nel raggiungimento degli obiettivi intermedi del quadro di riferimento dell’efficacia dell’attuazione di cui all’articolo 16 del regolamento (UE) 2021/1060 e delle lacune individuate in materia di attuazione.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Azioni specifiche", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può ricevere finanziamenti per azioni specifiche in aggiunta alla propria dotazione a norma dell’articolo 13, paragrafo 1, purché tali finanziamenti siano successivamente destinati come tali nel proprio programma e siano usati per contribuire alla realizzazione degli obiettivi del Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I finanziamenti per azioni specifiche non possono essere usati per altre azioni del programma dello Stato membro, tranne in casi debitamente giustificati e previa approvazione della Commissione mediante modifica del programma dello Stato membro.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Risorse per il reinsediamento e l’ammissione umanitaria", "anchor": "art_19", "frags": [[null, "<p class=\"modref\">\n▼M2\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In aggiunta alla rispettiva dotazione a norma dell’articolo 13, paragrafo 1, lettera a), del presente regolamento, gli Stati membri ricevono un importo di 10 000  EUR per ogni persona ammessa tramite reinsediamento nell’ambito del quadro dell’Unione per il reinsediamento e l’ammissione umanitaria istituito dal regolamento (UE) 2024/1350.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In aggiunta alla rispettiva dotazione di cui all’articolo 13, paragrafo 1, lettera a), del presente regolamento, gli Stati membri ricevono un importo di 6 000  EUR per ogni persona ammessa tramite ammissione umanitaria nell’ambito del quadro dell’Unione per il reinsediamento e l’ammissione umanitaria istituito a norma del regolamento (UE) 2024/1350 o ammessa nell’ambito di un programma nazionale di reinsediamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’importo di cui al paragrafo 2 è aumentato a 8 000  EUR per ogni persona ammessa tramite ammissione umanitaria o ammessa nell’ambito di un programma nazionale di reinsediamento che appartiene a uno o più dei seguenti gruppi vulnerabili:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">donne e minori a rischio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">minori non accompagnati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone con esigenze mediche che possono essere affrontate solo tramite ammissione umanitaria;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che necessitano di ammissione umanitaria per ragioni di protezione giuridica o fisica, comprese le vittime di violenza o tortura.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che ammette una persona appartenente a più di una delle categorie di cui ai paragrafi 2 e 3 riceve l’importo una sola volta per tale persona.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se del caso, gli Stati membri possono essere ammissibili a ricevere i rispettivi importi anche per i familiari delle persone di cui ai paragrafi 1, 2 e 3 se tali familiari sono ammessi per garantire l’unità familiare.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli importi di cui al presente articolo assumono la forma di finanziamento non collegato ai costi in conformità dell’articolo 125 del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli importi di cui ai paragrafi 1, 2, 3 e 5 sono assegnati al programma dello Stato membro per la prima volta nella decisione di finanziamento che approva tale programma. Tali importi non devono essere usati per altre azioni del programma dello Stato membro, tranne in casi debitamente giustificati e previa approvazione della Commissione mediante modifica di detto programma. Detti importi possono essere inclusi nelle domande di pagamento presentate alla Commissione, a condizione che la persona per la quale è stato assegnato l’importo sia stata effettivamente reinsediata o ammessa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Ai fini di controllo e audit, gli Stati membri conservano le informazioni necessarie per la corretta identificazione delle persone reinsediate o ammesse e per determinare con esattezza la data del loro reinsediamento o della loro ammissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Al fine di tenere conto degli attuali tassi di inflazione, dei pertinenti sviluppi in materia di reinsediamento e di altri fattori che potrebbero ottimizzare l’impiego dell’incentivo finanziario arrecato dagli importi di cui ai paragrafi 1, 2 e 3 del presente articolo, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 per adattare, se giudicato opportuno, tali importi nei limiti delle risorse disponibili.</div>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Risorse per il trasferimento di richiedenti protezione internazionale o di beneficiari di protezione internazionale", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In aggiunta alla dotazione a norma dell’articolo 13, paragrafo 1, lettera a), del presente regolamento, uno Stato membro riceve un importo pari a:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">10 000  EUR per richiedente protezione internazionale per il quale tale Stato membro diventa competente a seguito della ricollocazione a norma degli articoli 67 e 68 del regolamento (UE) 2024/1351;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">10 000  EUR per beneficiario di protezione internazionale ricollocato in tale Stato membro a norma degli articoli 67 e 68 del regolamento (UE) 2024/1351.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli importi di cui al primo comma, lettere a) e b), sono aumentati a 12 000  EUR rispettivamente per ciascun richiedente protezione internazionale o beneficiario di protezione internazionale che sia un minore non accompagnato ricollocato in tale Stato membro a norma degli articoli 67 e 68 del regolamento (UE) 2024/1351.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che copre il costo dei trasferimenti di cui al paragrafo 1 riceve un contributo di 500 EUR per ciascun richiedente protezione internazionale o beneficiario di protezione internazionale trasferito in un altro Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro che copre il costo dei trasferimenti di cui all’articolo 36, paragrafo 1, lettera a), b) o c), del regolamento (UE) 2024/1351, effettuati a norma dell’articolo 46 di tale regolamento, riceve un contributo di 500 EUR per ciascun richiedente protezione internazionale trasferito in un altro Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli importi di cui ai paragrafi da 1 a 3 del presente articolo sono assegnati al programma dello Stato membro, a condizione che la persona per la quale è stato assegnato l’importo sia stata effettivamente trasferita in tale Stato membro o registrata come richiedente nello Stato membro competente in conformità del regolamento (UE) 2024/1351, a seconda dei casi. Tali importi non devono essere usati per altre azioni del programma dello Stato membro, tranne in casi debitamente giustificati, previa approvazione della Commissione mediante modifica di tale programma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli importi di cui al presente articolo assumono la forma di finanziamento non collegato ai costi in conformità dell’articolo 125 del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ai fini di controllo e audit, gli Stati membri conservano le informazioni necessarie per la corretta identificazione delle persone trasferite e della data del loro trasferimento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Al fine di tenere conto degli attuali tassi di inflazione, dei pertinenti sviluppi in materia di ricollocazione e di altri fattori che potrebbero ottimizzare l’utilizzo dell’incentivo finanziario arrecato dagli importi di cui ai paragrafi 1, 2 e 3 del presente articolo, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 per adattare, se giudicato opportuno, tali importi nei limiti delle risorse disponibili.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Sostegno operativo", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può utilizzare fino al 15 % dell’importo stanziato per il suo programma nell’ambito del Fondo per finanziare il sostegno operativo nell’ambito degli obiettivi specifici del Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando utilizza il sostegno operativo uno Stato membro si conforma al pertinente acquis dell’Unione e alla Carta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Uno Stato membro illustra, nel proprio programma e nella relazione annuale in materia di performance di cui all’articolo 35 del presente regolamento, in che modo l’uso del sostegno operativo contribuisca al conseguimento degli obiettivi del Fondo. Prima dell’approvazione del programma dello Stato membro, la Commissione valuta la situazione di partenza negli Stati membri che hanno espresso l’intenzione di usare il sostegno operativo. La Commissione tiene conto delle informazioni fornite da tali Stati membri e, se del caso, delle informazioni disponibili a seguito degli esercizi di sorveglianza svolti in conformità del regolamento (UE) n. 1053/2013 e rientranti nell’ambito di applicazione del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il sostegno operativo si concentra sulle azioni coperte dai costi di cui all’allegato VII.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per far fronte a circostanze impreviste o nuove o per garantire l’efficace esecuzione dei finanziamenti, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 per modificare le azioni ammissibili elencate nell’allegato VII.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Verifiche di gestione e audit di progetti eseguiti da organizzazioni internazionali", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente articolo si applica alle organizzazioni internazionali o loro agenzie, di cui all’articolo 62, paragrafo 1, primo comma, lettera c), punto ii), del regolamento finanziario, i cui sistemi, norme e procedure sono stati valutati positivamente dalla Commissione a norma dell’articolo 154, paragrafi 4 e 7, di detto regolamento, ai fini dell’esecuzione indiretta di sovvenzioni finanziate a titolo del bilancio dell’Unione («organizzazioni internazionali»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatti salvi l’articolo 83, primo comma, lettera a), del regolamento (UE) 2021/1060 e l’articolo 129 del regolamento finanziario, se l’organizzazione internazionale è un beneficiario quale definito all’articolo 2, punto 9), del regolamento (UE) 2021/1060, l’autorità di gestione non è tenuta a effettuare le verifiche di gestione di cui all’articolo 74, paragrafo 1, primo comma, lettera a), del regolamento (UE) 2021/1060, a condizione che l’organizzazione internazionale trasmetta all’autorità di gestione i documenti di cui all’articolo 155, paragrafo 1, primo comma, lettere a), b) e c), del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 155, paragrafo 1, primo comma, lettera c), del regolamento finanziario, la dichiarazione di gestione che deve essere presentata dall’organizzazione internazionale conferma che il progetto rispetta il diritto applicabile e le condizioni per il suo sostegno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Inoltre, se i costi devono essere rimborsati a norma dell’articolo 53, paragrafo 1, lettera a), del regolamento (UE) 2021/1060, la dichiarazione di gestione che deve essere presentata dall’organizzazione internazionale conferma che siano state verificate:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le fatture e la prova del loro pagamento da parte del beneficiario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le registrazioni contabili o i codici contabili tenuti dal beneficiario per le operazioni collegate alle spese dichiarate all’autorità di gestione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se i costi devono essere rimborsati a norma dell’articolo 53, paragrafo 1, lettera b), c) o d), del regolamento (UE) 2021/1060, la dichiarazione di gestione che deve essere presentata dall’organizzazione internazionale conferma che siano state rispettate le condizioni per il rimborso delle spese.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">I documenti di cui all’articolo 155, paragrafo 1, primo comma, lettere a) e c), del regolamento finanziario sono forniti all’autorità di gestione unitamente a ciascuna domanda di pagamento presentata dal beneficiario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Ogni anno, entro il 15 ottobre il beneficiario presenta all’autorità di gestione i conti corredati del parere di un organismo di audit indipendente, elaborato conformemente ai principi di audit riconosciuti a livello internazionale. Detto parere accerta che i sistemi di controllo istituiti funzionino correttamente e siano efficaci in termini di costi e che le operazioni sottostanti siano legittime e regolari. Tale parere riferisce altresì se l’esercizio di audit mette in dubbio le asserzioni contenute nelle dichiarazioni di gestione presentate dall’organizzazione internazionale, comprese le informazioni sui sospetti di frode. Detto parere fornisce garanzie che le spese incluse nelle domande di pagamento presentate dall’organizzazione internazionale all’autorità di gestione sono legali e regolari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Fatte salve le possibilità esistenti di effettuare ulteriori audit di cui all’articolo 127 del regolamento finanziario, l’autorità di gestione redige la dichiarazione di gestione di cui all’articolo 74, paragrafo 1, primo comma, lettera f), del regolamento (UE) 2021/1060 sulla base dei documenti forniti dall’organizzazione internazionale ai sensi dei paragrafi da 2 a 5 e 7 del presente articolo, anziché basarsi sulle verifiche di gestione di cui all’articolo 74, paragrafo 1, del regolamento (UE) 2021/1060.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Il documento che specifica le condizioni per il sostegno di cui all’articolo 73, paragrafo 3, del regolamento (UE) 2021/1060 comprende i requisiti di cui al presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il paragrafo 2 non si applica e, di conseguenza, un’autorità di gestione è tenuta a svolgere le verifiche di gestione, se:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tale autorità di gestione individua un rischio specifico di irregolarità o un’indicazione di frode in relazione a un progetto avviato o attuato dall’organizzazione internazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’organizzazione internazionale non presenta a tale autorità di gestione i documenti di cui ai paragrafi da 2 a 5 e 7;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i documenti di cui ai paragrafi da 2 a 5 e 7 presentati dall’organizzazione internazionale sono incompleti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Se un progetto in cui un’organizzazione internazionale è un beneficiario ai sensi dell’articolo 2, punto 9), del regolamento (UE) 2021/1060, fa parte di un campione di cui all’articolo 79 di tale regolamento, l’autorità di audit può svolgere il proprio lavoro sulla base di un sottocampione di operazioni riguardante tale progetto. Se nel sottocampione sono riscontrati errori, l’autorità di audit, se del caso, può chiedere al revisore dell’organizzazione internazionale di valutare l’intera portata e l’importo totale degli errori in detto progetto.</div>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Ambito di applicazione", "anchor": "art_23", "frags": [[null, "<p class=\"norm\">La Commissione dà attuazione al sostegno di cui alla presente sezione direttamente, in conformità dell’articolo 62, paragrafo 1, primo comma, lettera a), del regolamento finanziario, o indirettamente in conformità della lettera c) del medesimo comma.</p>"]]}, "24": {"label": "Articolo 24", "heading": "Soggetti idonei", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono ammissibili al finanziamento dell’Unione i seguenti soggetti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i soggetti giuridici stabiliti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in uno Stato membro o un paese o territorio d’oltremare a esso connesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in un paese terzo associato al Fondo in forza di un accordo specifico a norma dell’articolo 7, subordinatamente alla sua inclusione nel programma di lavoro e alle condizioni ivi contenute;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in un paese terzo elencato nel programma di lavoro, alle condizioni specificate al paragrafo 3;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i soggetti giuridici costituiti a norma del diritto dell’Unione o le organizzazioni internazionali pertinenti ai fini del Fondo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Non sono ammissibili al finanziamento dell’Unione le persone fisiche.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I soggetti di cui al paragrafo 1, lettera a), punto iii), partecipano nell’ambito di un consorzio costituito da almeno due soggetti indipendenti, di cui almeno uno è stabilito in uno Stato membro.</div>\n</div>"], [null, "<p class=\"norm\">I soggetti che partecipano nell’ambito di un consorzio di cui al primo comma del presente paragrafo garantiscono che le azioni a cui partecipano rispettino i principi sanciti dalla Carta e contribuiscano al conseguimento degli obiettivi del Fondo.</p>"]]}, "25": {"label": "Articolo 25", "heading": "Azioni dell’Unione", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Su iniziativa della Commissione, il Fondo può finanziare azioni dell’Unione riguardanti gli obiettivi del Fondo conformemente all’allegato III.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le azioni dell’Unione possono concedere finanziamenti in tutte le forme previste dal regolamento finanziario, segnatamente sovvenzioni, premi e appalti. Esse possono inoltre concedere finanziamenti sotto forma di strumenti finanziari nell’ambito di operazioni di finanziamento misto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le sovvenzioni attuate in regime di gestione diretta sono concesse e gestite conformemente al titolo VIII del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I membri del comitato di valutazione, che valuta le proposte, di cui all’articolo 150 del regolamento finanziario, possono essere esperti esterni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I contributi a un meccanismo di mutua assicurazione possono coprire il rischio associato al recupero dei fondi dovuti dai destinatari e sono considerati una garanzia sufficiente a titolo del regolamento finanziario. Si applica l’articolo 37, paragrafo 7, del regolamento (UE) 2021/695 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">4</span>\n).</div>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Rete europea sulle migrazioni", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il Fondo sostiene la rete europea sulle migrazioni e fornisce il sostegno finanziario necessario per le sue attività e il suo sviluppo futuro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’importo messo a disposizione della rete europea sulle migrazioni nell’ambito degli stanziamenti annuali del Fondo e il programma di lavoro che fissa le priorità delle sue attività sono adottati dalla Commissione previa approvazione da parte del comitato direttivo in conformità dell’articolo 4, paragrafo 5, lettera a), della decisione 2008/381/CE. La decisione della Commissione costituisce una decisione di finanziamento a norma dell’articolo 110 del regolamento finanziario. Per garantire la tempestiva disponibilità delle risorse, la Commissione può adottare il programma di lavoro della rete europea sulle migrazioni con una decisione di finanziamento distinta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’assistenza finanziaria prevista per le attività della rete europea sulle migrazioni assume la forma di sovvenzioni a favore dei punti di contatto nazionali di cui all’articolo 3 della decisione 2008/381/CE o di appalti pubblici, a seconda dei casi, in conformità del regolamento finanziario.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Operazioni di finanziamento misto", "anchor": "art_27", "frags": [[null, "<p class=\"norm\">Le operazioni di finanziamento misto nell’ambito del Fondo sono eseguite in conformità del regolamento (UE) 2021/523 e del titolo X del regolamento finanziario.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Assistenza tecnica su iniziativa della Commissione", "anchor": "art_28", "frags": [[null, "<p class=\"norm\">In conformità dell’articolo 35 del regolamento (UE) 2021/1060, il Fondo può sostenere l’assistenza tecnica attuata su iniziativa o per conto della Commissione a un tasso di finanziamento del 100 %.</p>"]]}, "29": {"label": "Articolo 29", "heading": "Audit", "anchor": "art_29", "frags": [[null, "<p class=\"norm\">Gli audit sull’uso del contributo dell’Unione effettuati da persone o soggetti anche diversi da quelli autorizzati dalle istituzioni, dagli organi o dagli organismi dell’Unione costituiscono la base della garanzia globale di affidabilità a norma dell’articolo 127 del regolamento finanziario.</p>"]]}, "30": {"label": "Articolo 30", "heading": "Informazione, comunicazione e pubblicità", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I destinatari dei finanziamenti dell’Unione rendono nota l’origine di tali finanziamenti e ne garantiscono la visibilità, in particolare quando promuovono azioni e risultati, fornendo informazioni coerenti, efficaci, significative e proporzionate a destinatari diversi, compresi i media e il pubblico. È garantita la visibilità dei finanziamenti dell’Unione e sono fornite dette informazioni, eccetto in casi debitamente giustificati in cui non sia possibile o appropriato esporre tali informazioni pubblicamente o laddove la divulgazione di tali informazioni sia soggetta a restrizioni per legge, in particolare per ragioni di sicurezza, ordine pubblico, indagini penali o protezione dei dati personali. Al fine di garantire la visibilità dei finanziamenti dell’Unione, i destinatari di tali finanziamenti fanno riferimento all’origine di tali finanziamenti quando comunicano pubblicamente informazioni in merito alle azioni in questione ed espongono l’emblema dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Al fine di raggiungere un pubblico che sia il più ampio possibile, la Commissione realizza azioni di informazione e comunicazione sul Fondo, sulle azioni intraprese nell’ambito del Fondo e sui risultati ottenuti.</div>\n</div>"], [null, "<p class=\"norm\">Le risorse finanziarie destinate al Fondo contribuiscono anche alla comunicazione istituzionale delle priorità politiche dell’Unione nella misura in cui tali priorità si riferiscono agli obiettivi del Fondo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione pubblica i programmi di lavoro dello strumento tematico di cui all’articolo 11. Per il sostegno fornito in regime di gestione diretta o indiretta, la Commissione pubblica le informazioni di cui all’articolo 38, paragrafo 2, del regolamento finanziario su un sito web accessibile al pubblico e aggiorna regolarmente tali informazioni. Tali informazioni sono pubblicate in un formato aperto e leggibile meccanicamente che consente di selezionare, ricercare, estrarre e comparare i dati.</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Assistenza emergenziale", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il Fondo fornisce sostegno finanziario per far fronte a necessità urgenti e specifiche nell’eventualità di situazioni di emergenza debitamente giustificate derivanti da una o più delle seguenti circostanze:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una situazione migratoria eccezionale caratterizzata da un afflusso massiccio o sproporzionato di cittadini di paesi terzi in uno o più Stati membri che ne sottopone le capacità di accoglienza e trattenimento nonché i sistemi e le procedure di asilo e di gestione della migrazione a considerevoli e urgenti sollecitazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un afflusso massiccio di sfollati ai sensi della direttiva 2001/55/CE del Consiglio (\n<span class=\"superscript\">5</span>\n);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M4\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una situazione di crisi ai sensi dell'articolo 1, paragrafo 4, lettera a), del regolamento (UE) 2024/1359 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">6</span>\n);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una situazione migratoria eccezionale in un paese terzo, in particolare qualora persone che necessitano di protezione rimangano bloccate a seguito di conflitti o sviluppi politici, specialmente se ciò può influire sui flussi migratori in direzione dell’Unione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In risposta a situazioni di emergenza debitamente giustificate, la Commissione può decidere di fornire assistenza emergenziale, anche per la ricollocazione volontaria, entro i limiti delle risorse disponibili. In tal caso, la Commissione informa tempestivamente il Parlamento europeo e il Consiglio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le misure nei paesi terzi sono attuate in conformità dell’articolo 5, paragrafi 2 e 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’assistenza emergenziale può essere assegnata ai programmi degli Stati membri in aggiunta alla dotazione a norma dell’articolo 13, paragrafo 1, e dell’allegato I, purché abbia tale conseguente destinazione nel programma dello Stato membro. Tale finanziamento non può essere usato per altre azioni del programma dello Stato membro, tranne in casi debitamente giustificati e previa approvazione della Commissione mediante modifica del programma. Il prefinanziamento per l’assistenza emergenziale può ammontare al 95 % del contributo dell’Unione, subordinatamente alla disponibilità di finanziamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le sovvenzioni attuate in regime di gestione diretta sono concesse e gestite conformemente al titolo VIII del regolamento finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Laddove necessario per realizzare un’azione, l’assistenza emergenziale può coprire le spese sostenute prima della data di presentazione della domanda di sovvenzione o della domanda di assistenza per tale azione, purché tali spese non siano state sostenute anteriormente al 1<span class=\"superscript\">o</span> gennaio 2021.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Per imperativi motivi di urgenza debitamente giustificati e per garantire la tempestiva disponibilità di risorse per l’assistenza emergenziale, la Commissione può adottare separatamente una decisione di finanziamento, di cui all’articolo 110 del regolamento finanziario, per l’assistenza emergenziale mediante un atto di esecuzione immediatamente applicabile secondo la procedura di cui all’articolo 38, paragrafo 4. Tale atto resta in vigore per un periodo non superiore a 18 mesi.</div>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Finanziamento cumulativo e alternativo", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un’azione che ha beneficiato di un contributo nell’ambito del Fondo può essere finanziata anche da un altro programma dell’Unione, compresi i fondi in regime di gestione concorrente, purché tali contributi non riguardino gli stessi costi. Al corrispondente contributo fornito all’azione si applicano le norme del pertinente programma dell’Unione. Il finanziamento cumulativo non supera i costi totali ammissibili dell’azione. Il sostegno proveniente dai diversi programmi dell’Unione può essere calcolato proporzionalmente in conformità dei documenti che specificano le condizioni per il sostegno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In conformità dell’articolo 73, paragrafo 4, del regolamento (UE) 2021/1060, il FESR o il FSE+ possono sostenere azioni a cui è stato attribuito un marchio di eccellenza come definito all’articolo 2, punto 45, di tale regolamento. Per vedersi attribuito un marchio di eccellenza, le azioni devono soddisfare le seguenti condizioni cumulative:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono state valutate nel quadro di un invito a presentare proposte nell’ambito del Fondo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono conformi ai requisiti minimi di qualità indicati nell’invito a presentare proposte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non possono essere finanziate nel quadro dell’invito a presentare proposte a causa di vincoli di bilancio.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "33": {"label": "Articolo 33", "heading": "Sorveglianza e rendicontazione", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Conformemente agli obblighi di rendicontazione a norma dell’articolo 41, paragrafo 3, primo comma, lettera h), punto iii), del regolamento finanziario, la Commissione trasmette al Parlamento europeo e al Consiglio informazioni sugli indicatori chiave di performance elencati nell’allegato V del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 per modificare l’allegato V allo scopo di apportare le modifiche necessarie agli indicatori chiave di performance elencati in tale allegato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli indicatori da utilizzare per rendere conto dei progressi del Fondo nel conseguire gli obiettivi specifici di cui all’articolo 3, paragrafo 2, figurano nell’allegato VIII. Per gli indicatori di output, i valori base sono fissati a zero. I target intermedi per il 2024 e i target finali per il 2029 sono cumulativi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il sistema di rendicontazione sulla performance garantisce che i dati per la sorveglianza dell’attuazione e i risultati del programma siano raccolti in modo efficiente, efficace e tempestivo. A tale scopo devono essere imposti obblighi di rendicontazione proporzionati ai destinatari dei finanziamenti dell’Unione e, se del caso, agli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Al fine di garantire l’efficace valutazione dei progressi del Fondo nel conseguire i suoi obiettivi, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 per modificare l’allegato VIII al fine di rivedere o completare gli indicatori, se ritenuto necessario, e di integrare il presente regolamento con disposizioni sull’istituzione di un quadro di sorveglianza e di valutazione, anche in relazione alle informazioni sul progetto che gli Stati membri devono fornire. Un’eventuale modifica dell’allegato VIII si applica soltanto ai progetti selezionati dopo l’entrata in vigore di tale modifica.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Valutazione", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Entro il 31 dicembre 2024 la Commissione effettua una valutazione intermedia del presente regolamento. Oltre a quanto previsto dall’articolo 45, paragrafo 1, del regolamento (UE) 2021/1060, la valutazione intermedia esamina quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’efficacia del Fondo, compresi i progressi compiuti nel conseguimento dei suoi obiettivi, tenendo conto di tutte le informazioni pertinenti disponibili, in particolare delle relazioni annuali in materia di performance di cui all’articolo 35 e degli indicatori di output e di risultato di cui all’allegato VIII;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’efficienza nell’uso delle risorse assegnate al Fondo e l’efficienza delle misure di gestione e di controllo messe in atto per la sua attuazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il sussistere della pertinenza e dell’adeguatezza delle misure di attuazione elencate nell’allegato II;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il coordinamento, la coerenza e la complementarità tra le azioni sostenute nell’ambito del Fondo e il sostegno fornito da altri fondi dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il valore aggiunto dell’Unione delle azioni attuate nell’ambito del Fondo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tale valutazione intermedia tiene conto dei risultati della valutazione retrospettiva degli effetti del Fondo Asilo, migrazione e integrazione per il periodo 2014-2020.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Oltre a quanto previsto nell’articolo 45, paragrafo 2, del regolamento (UE) 2021/1060, la valutazione retrospettiva comprende gli elementi elencati al paragrafo 1. Va inoltre valutato l’impatto del Fondo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La valutazione intermedia e la valutazione retrospettiva sono effettuate con tempestività per contribuire al processo decisionale, compresa, se del caso, la revisione del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nella valutazione intermedia e nella valutazione retrospettiva, la Commissione presta particolare attenzione alla valutazione delle azioni attuate con paesi terzi, in tali paesi o in relazione a essi, conformemente all’articolo 7, all’articolo 16, paragrafo 11, e all’articolo 24.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Relazioni annuali in materia di performance", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 15 febbraio 2023 ed entro il 15 febbraio di ogni anno successivo fino al 2031 compreso, gli Stati membri trasmettono alla Commissione la relazione annuale in materia di performance di cui all’articolo 41, paragrafo 7, del regolamento (UE) 2021/1060.</div>\n</div>"], [null, "<p class=\"norm\">Il periodo di riferimento copre l’ultimo periodo contabile, come definito all’articolo 2, punto 29, del regolamento (UE) 2021/1060, precedente l’anno di trasmissione della relazione. La relazione presentata entro il 15 febbraio 2023 copre il periodo che decorre dal 1<span class=\"superscript\">o</span> gennaio 2021.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La relazione annuale in materia di performance contiene in particolare informazioni riguardanti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nell’attuazione del programma dello Stato membro e nel conseguimento dei target intermedi e target finali ivi previsti, tenuto conto dei dati più recenti come richiesto a norma dell’articolo 42 del regolamento (UE) 2021/1060;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tutte le questioni che incidono sulla performance del programma dello Stato membro e le misure adottate per farvi fronte, ivi comprese informazioni su pareri motivati espressi dalla Commissione in relazione a una procedura d’infrazione a norma dell’articolo 258 TFUE connessa all’attuazione del Fondo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la complementarità tra le azioni sostenute nell’ambito del Fondo e il sostegno fornito da altri fondi dell’Unione, in particolare quelle azioni intraprese nei paesi terzi o in relazione a tali paesi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo del programma dello Stato membro all’attuazione dell’acquis e dei piani d’azione dell’Unione pertinenti nonché alla cooperazione e alla solidarietà fra Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione di azioni di comunicazione e di visibilità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il soddisfacimento delle condizioni abilitanti applicabili e la loro applicazione durante l’intero periodo di programmazione, in particolare il rispetto dei diritti fondamentali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di persone ammesse mediante il reinsediamento e l’ammissione umanitaria con riferimento agli importi stabiliti all’articolo 19;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richiedenti e di beneficiari di protezione internazionale trasferiti da uno Stato membro a un altro in conformità dell’articolo 20;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M3\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h bis) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione delle azioni di solidarietà, compresa una ripartizione dei contributi finanziari per azione e una descrizione dei principali risultati conseguiti grazie ai finanziamenti;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione di progetti in un paese terzo o in relazione a un paese terzo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le relazioni annuali in materia di performance comprendono una sintesi relativa a tutti i punti di cui al primo comma del presente paragrafo. La Commissione provvede affinché le sintesi fornite dagli Stati membri siano tradotte in tutte le lingue ufficiali dell’Unione e rese pubbliche.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione ha la facoltà di formulare osservazioni in merito alla relazione annuale in materia di performance entro due mesi dalla data di ricezione. Qualora la Commissione non esprima osservazioni entro tale termine, la relazione s’intende accettata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Sul suo sito web, la Commissione fornisce i link ai siti web di cui all’articolo 49, paragrafo 1, del regolamento (UE) 2021/1060.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Al fine di garantire condizioni uniformi di esecuzione del presente articolo, la Commissione adotta un atto di esecuzione che stabilisce il modello della relazione annuale in materia di performance. Tale atto di esecuzione è adottato secondo la procedura consultiva di cui all’articolo 38, paragrafo 2.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Sorveglianza e rendicontazione in regime di gestione concorrente", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La sorveglianza e la rendicontazione di cui al titolo IV del regolamento (UE) 2021/1060 utilizzano, ove opportuno, i codici per le tipologie di intervento indicate nell’allegato VI del presente regolamento. Per far fronte a circostanze impreviste o nuove e per garantire l’efficiente attuazione dei finanziamenti, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 37 del presente regolamento per modificare l’allegato VI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli indicatori definiti nell’allegato VIII del presente regolamento sono usati conformemente all’articolo 16, paragrafo 1, e agli articoli 22 e 42 del regolamento (UE) 2021/1060.</div>\n</div>"]]}, "37": {"label": "Articolo 37", "heading": "Esercizio della delega", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all’articolo 5, paragrafo 1, secondo comma, all’articolo 16, paragrafo 9, all’articolo 19, paragrafo 9, all’articolo 20, paragrafo 9, all’articolo 21, paragrafo 5, all’articolo 33, paragrafi 2 e 5, e all’articolo 36, paragrafo 1, è conferito alla Commissione fino al 31 dicembre 2027.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all’articolo 5, paragrafo 1, secondo comma, all’articolo 16, paragrafo 9, all’articolo 19, paragrafo 9, all’articolo 20, paragrafo 9, all’articolo 21, paragrafo 5, all’articolo 33, paragrafi 2 e 5, e all’articolo 36, paragrafo 1, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Prima dell’adozione dell’atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell’accordo interistituzionale «Legiferare meglio» del 13 aprile 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’atto delegato adottato ai sensi dell’articolo 5, paragrafo 1, secondo comma, dell’articolo 16, paragrafo 9, dell’articolo 19, paragrafo 9, dell’articolo 20, paragrafo 9, dell’articolo 21, paragrafo 5, dell’articolo 33, paragrafi 2 o 5, o dell’articolo 36, paragrafo 1, entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"]]}, "38": {"label": "Articolo 38", "heading": "Procedura di comitato", "anchor": "art_38", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita dal comitato per i fondi per gli affari interni, istituito dall’articolo 32 del regolamento (UE) 2021/1148 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">7</span>\n). Esso è un comitato ai sensi del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 4 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"norm\">Qualora il comitato non esprima alcun parere, la Commissione non adotta il progetto di atto di esecuzione e si applica l’articolo 5, paragrafo 4, terzo comma, del regolamento (UE) n. 182/2011.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 8 del regolamento (UE) n. 182/2011 in combinato disposto con il suo articolo 5.</div>\n</div>"]]}, "39": {"label": "Articolo 39", "heading": "Disposizioni transitorie", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento non pregiudica il proseguimento o la modifica delle azioni avviate a norma del regolamento (UE) n. 516/2014, che continua pertanto ad applicarsi a tali azioni fino alla loro chiusura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La dotazione finanziaria del Fondo può anche coprire le spese di assistenza tecnica e amministrativa necessarie per assicurare la transizione tra il Fondo e le misure adottate a norma del regolamento (UE) n. 516/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai sensi dell’articolo 193, paragrafo 2, secondo comma, lettera a), del regolamento finanziario, tenuto conto del ritardo nell’entrata in vigore del presente regolamento e al fine di garantire la continuità, per un periodo limitato i costi sostenuti in relazione ad azioni già avviate che beneficiano di sostegno a norma del presente regolamento in regime di gestione diretta possono essere considerati ammissibili al finanziamento a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2021, anche se tali costi sono stati sostenuti prima della presentazione della domanda di sovvenzione o della domanda di assistenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri possono continuare dopo il 1<span class=\"superscript\">o</span> gennaio 2021 a sostenere un progetto selezionato e avviato a norma del regolamento (UE) n. 516/2014, conformemente al regolamento (UE) n. 514/2014, purché siano soddisfatte tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il progetto presenta due fasi distinguibili sotto l’aspetto finanziario e piste di controllo distinte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il costo totale del progetto è superiore a 500 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i pagamenti versati ai beneficiari dall’autorità responsabile per la prima fase del progetto sono inclusi nelle richieste di pagamento trasmesse alla Commissione a norma del regolamento (UE) n. 514/2014 e le spese per la seconda fase del progetto sono incluse nelle domande di pagamento a norma del regolamento (UE) 2021/1060;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la seconda fase del progetto ottempera al diritto applicabile ed è ammissibile al sostegno del Fondo a norma del presente regolamento e del regolamento (UE) 2021/1060;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo Stato membro si impegna a completare il progetto, a renderlo operativo e a riferirne nella relazione annuale in materia di performance presentata entro il 15 febbraio 2024.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le disposizioni del presente regolamento e del regolamento (UE) 2021/1060 si applicano alla seconda fase di un progetto di cui al primo comma del presente paragrafo.</p>"], [null, "<p class=\"norm\">Il presente paragrafo si applica solo ai progetti selezionati in regime di gestione concorrente a norma del regolamento (UE) n. 514/2014.</p>"]]}, "40": {"label": "Articolo 40", "heading": "Entrata in vigore e applicazione", "anchor": "art_40", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il giorno della pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"norm\">Esso si applica a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2021.</p>"]]}}, "recitals": {}};